function testMyJSON(v) {
	try {
		console.log(`==== real value ====`);
		console.log(v)
		console.log(`==== myJSON() ====`)
		console.log(myJSON.stringify(v))
		console.log(`==== JSON() ====`)
		console.log(JSON.stringify(v))
		console.log(`==== RESULT ====`)
		console.log(myJSON.stringify(v) === JSON.stringify(v))
		console.log("\n")
	} catch (e) {
		console.error(e)
	}

}

tests.map(test => testMyJSON(test))
